function desanitizeAndInjectCSS(htmlString,cssString){const desanitizedHtml=htmlString.replace(/&lt;/g,"<").replace(/&gt;/g,">").replace(/&quot;/g,'"').replace(/&apos;/g,"'").replace(/&amp;/g,"&");const parser=new DOMParser;const doc=parser.parseFromString(desanitizedHtml,"text/html");const styleTag=document.createElement("style");styleTag.textContent=cssString;doc.head.appendChild(styleTag);return"<!DOCTYPE html>\n"+doc.documentElement.outerHTML}const CACHE_CONFIG={duration:5*60*1e3,prefix:"gblocks_dynamic_",enabled:true};const CacheManager={get(key){if(!CACHE_CONFIG.enabled)return null;try{const cacheKey=CACHE_CONFIG.prefix+key;const cached=localStorage.getItem(cacheKey);if(!cached)return null;const{data,timestamp}=JSON.parse(cached);const now=Date.now();if(now-timestamp>CACHE_CONFIG.duration){localStorage.removeItem(cacheKey);return null}console.log(`📦 Cache HIT for ${key}`);return data}catch(error){console.warn("Cache get error:",error);return null}},set(key,data){if(!CACHE_CONFIG.enabled)return;try{const cacheKey=CACHE_CONFIG.prefix+key;const cacheData={data:data,timestamp:Date.now()};localStorage.setItem(cacheKey,JSON.stringify(cacheData));console.log(`💾 Cache SET for ${key}`)}catch(error){console.warn("Cache set error:",error);if(error.name==="QuotaExceededError"){this.clearExpired()}}},clearExpired(){const now=Date.now();const keysToRemove=[];for(let i=0;i<localStorage.length;i++){const key=localStorage.key(i);if(key&&key.startsWith(CACHE_CONFIG.prefix)){try{const cached=JSON.parse(localStorage.getItem(key));if(now-cached.timestamp>CACHE_CONFIG.duration){keysToRemove.push(key)}}catch(error){keysToRemove.push(key)}}}keysToRemove.forEach(key=>localStorage.removeItem(key));console.log(`🧹 Cleared ${keysToRemove.length} expired cache entries`)},clearAll(){const keysToRemove=[];for(let i=0;i<localStorage.length;i++){const key=localStorage.key(i);if(key&&key.startsWith(CACHE_CONFIG.prefix)){keysToRemove.push(key)}}keysToRemove.forEach(key=>localStorage.removeItem(key));console.log(`🗑️ Cleared all ${keysToRemove.length} cache entries`)}};async function fetchDynamicData(dataType){const endpoints={posts:`/api/v1/design/dynamic/posts`,authors:`/api/v1/design/dynamic/authors`,tags:`/api/v1/design/dynamic/tags`,pages:`/api/v1/design/dynamic/pages`,nav:`/api/v1/design/dynamic/nav`};const endpoint=endpoints[dataType];if(!endpoint){console.warn(`Unknown data type: ${dataType}`);return[]}const cachedData=CacheManager.get(dataType);if(cachedData){return cachedData}try{console.log(`🌐 Fetching fresh ${dataType} data from API...`);const response=await fetch(`https://api.bloxear.com${endpoint}`);const result=await response.json();if(result.statusCode===200&&result.data){CacheManager.set(dataType,result.data);return result.data}console.warn(`No data found for ${dataType}:`,result);return[]}catch(error){console.error(`Error fetching ${dataType} data:`,error);return[]}}function getNestedPropertyValue(obj,path){if(!obj||!path)return"";return path.split(".").reduce((current,key)=>{return current&&current[key]!==undefined?current[key]:""},obj)}function sortData(data,sortBy,sortOrder){if(!data||!Array.isArray(data)||!sortBy)return data;const sorted=[...data].sort((a,b)=>{const aVal=getNestedPropertyValue(a,sortBy);const bVal=getNestedPropertyValue(b,sortBy);if(typeof aVal==="string"&&typeof bVal==="string"){return sortOrder==="desc"?bVal.localeCompare(aVal):aVal.localeCompare(bVal)}if(aVal instanceof Date&&bVal instanceof Date){return sortOrder==="desc"?bVal-aVal:aVal-bVal}const aDate=new Date(aVal);const bDate=new Date(bVal);if(!isNaN(aDate)&&!isNaN(bDate)){return sortOrder==="desc"?bDate-aDate:aDate-bDate}return sortOrder==="desc"?String(bVal).localeCompare(String(aVal)):String(aVal).localeCompare(String(bVal))});return sorted}function applyCharacterLimit(value,limit){if(!limit||limit<=0)return value;const textOnly=value.replace(/<[^>]*>/g,"");if(textOnly.length<=limit){return value}if(value!==textOnly){return textOnly.substring(0,limit)+"..."}return value.substring(0,limit)+"..."}function populateTemplate(template,itemData){const clone=template.cloneNode(true);clone.removeAttribute("data-item-template");clone.style.display="";clone.classList.remove("dynamic-item-template");const bindElements=clone.querySelectorAll("[data-bind-field]");bindElements.forEach(element=>{const fieldPath=element.getAttribute("data-bind-field");const value=getNestedPropertyValue(itemData,fieldPath);if(value){switch(element.tagName.toLowerCase()){case"img":element.src=value;element.alt=element.alt||getNestedPropertyValue(itemData,"title")||"Image";break;case"a":if(fieldPath.includes("url")||fieldPath.includes("link")||fieldPath.includes("href")){element.href=value}else{const limit=parseInt(element.getAttribute("data-bind-limit"));const limitedValue=applyCharacterLimit(value,limit);element.textContent=limitedValue}break;case"input":element.value=value;break;default:const limit=parseInt(element.getAttribute("data-bind-limit"));const limitedValue=applyCharacterLimit(value,limit);element.textContent=limitedValue;break}}});return clone}async function processDynamicContainers(designData){const dynamicContainers=document.querySelectorAll("[data-dynamic-type]");console.log(`🔗 Found ${dynamicContainers.length} dynamic containers`);if(designData&&designData.dynamicBindings&&designData.dynamicBindings.containers&&designData.dynamicBindings.containers.length>0){console.log("📊 Dynamic bindings found:",designData.dynamicBindings)}for(const container of dynamicContainers){const dataType=container.getAttribute("data-dynamic-type");const itemCount=parseInt(container.getAttribute("data-item-count"))||6;const sortBy=container.getAttribute("data-sort-by")||"published_at";const sortOrder=container.getAttribute("data-sort-order")||"desc";console.log(`📊 Processing ${dataType} container:`,{itemCount:itemCount,sortBy:sortBy,sortOrder:sortOrder,containerId:container.id});const template=container.querySelector('[data-item-template="true"]');if(!template){console.warn(`❌ No template found in ${dataType} container`);continue}try{const data=await fetchDynamicData(dataType);console.log(data);if(!data||data.length===0){console.warn(`📭 No data found for ${dataType}`);container.style.display="none";continue}const sortedData=sortData(data,sortBy,sortOrder);const limitedData=sortedData.slice(0,itemCount);console.log(`✅ Processing ${limitedData.length} ${dataType} items`);const fragment=document.createDocumentFragment();limitedData.forEach((itemData,index)=>{const populatedItem=populateTemplate(template,itemData);populatedItem.setAttribute("data-item-index",index.toString());fragment.appendChild(populatedItem)});container.appendChild(fragment);console.log(`🎉 Successfully populated ${dataType} container with ${limitedData.length} items`)}catch(error){console.error(`❌ Error processing ${dataType} container:`,error);container.style.display="none"}}}async function loader(){CacheManager.clearExpired();let slug=window.location.pathname.replace(/^\/+|\/+$/g,"");if(!slug)slug="home";try{const response=await fetch("https://api.bloxear.com/api/v1/design/data",{headers:{slug:slug}});const designData=await response.json();console.log("designData",designData);const parseDesignData=JSON.parse(designData.data.designData);const generateHTML=desanitizeAndInjectCSS(parseDesignData.html,parseDesignData.css);console.log("html",generateHTML);document.write(generateHTML);console.log("🔄 Processing dynamic containers...");await processDynamicContainers(parseDesignData);console.log("✅ Dynamic container processing complete");document.getElementById("page-preloader")?.remove();document.body.style.display="block"}catch(err){console.error("❌ Loader error:",err);document.body.style.display="block"}}window.GBlocksCache={clear:()=>CacheManager.clearAll(),clearExpired:()=>CacheManager.clearExpired(),config:CACHE_CONFIG,setDuration:minutes=>{CACHE_CONFIG.duration=minutes*60*1e3;console.log(`Cache duration set to ${minutes} minutes`)},enable:()=>{CACHE_CONFIG.enabled=true;console.log("Cache enabled")},disable:()=>{CACHE_CONFIG.enabled=false;console.log("Cache disabled")}};loader();